function loadCatalogIds() {
  const ids = new Set()
  for (const file of readdirSync(join(process.cwd(), 'schema', 'categories')).filter(f => f.endsWith('.json'))) {
    const cat = JSON.parse(readFileSync(join(process.cwd(), 'schema', 'categories', file), 'utf8'))
    for (const element of cat.elements) ids.add(element.id)
  }
  return ids
}

function patchSourceUrls(text) {
  return text
}

const catalogIds = loadCatalogIds()

for (const [id, update] of Object.entries(updates)) {
  const file = join(examplesDir, `${id}.json`)
  const doc = JSON.parse(readFileSync(file, 'utf8'))
  if (update.software_version) doc.software_version = update.software_version
  if (update.effective_date) doc.effective_date = update.effective_date
  doc.boundary_combinations = update.boundary_combinations
  doc.metadata = doc.metadata || {}
  doc.metadata.evidence_as_of = TODAY
  if (update.sources) doc.metadata.sources = update.sources
  if (doc.metadata.sources) doc.metadata.sources = doc.metadata.sources.map(patchSourceUrls)

  for (const c of doc.boundary_combinations) {
    for (const elementId of c.related_element_ids || []) {
      if (!catalogIds.has(elementId)) {
        throw new Error(`${id}/${c.id} references unknown element id: ${elementId}`)
      }
    }
  }

  let text = JSON.stringify(doc, null, 2) + '\n'
  text = patchSourceUrls(text)
  writeFileSync(file, text, 'utf8')
  console.log(`${id}: ${doc.boundary_combinations.length} boundary combinations`)
}
